}

(* MindLang Example: Ensemble Voting
   Demonstrates multi-path reasoning with consensus voting

   This example shows:
   - Query specification
   - Three independent reasoning paths
   - Parallel execution with fork
   - Consensus voting among paths
   - Confidence-based result selection
   - Output formatting
*)

program ensemble_voting {
  (* Input query *)
  query "What is the capital of France?" -> input

  (* Encode query *)
  encode input -> z

  (* Fork into three independent reasoning branches *)
  fork z -> {z_path_a, z_path_b, z_path_c}

  (* Execute three reasoning paths in parallel *)
  path_a = solve_with_path_a(z_path_a)
  path_b = solve_with_path_b(z_path_b)
  path_c = solve_with_path_c(z_path_c)

  (* Collect all results *)
  results = [path_a, path_b, path_c]

  (* Compute confidence scores for each result *)
  conf_a = confidence_score(path_a)
  conf_b = confidence_score(path_b)
  conf_c = confidence_score(path_c)
  confidences = [conf_a, conf_b, conf_c]

  (* Apply weighted voting consensus *)
  consensus_result = weighted_vote results confidences

  (* Calculate overall agreement level *)
  agreement = compute_agreement_level results

  (* If agreement is high, return consensus *)
  if agreement > 0.8 {
    detokenize consensus_result -> output
    return output
  } else {
    (* If agreement is low, select highest confidence result *)
    ranked = rank_results confidences
    best_idx = ranked[0]
    best_result = results[best_idx]
    detokenize best_result -> output
    return output
  }
}

(* First reasoning path: Rule-based *)
fn solve_with_path_a(z: LatentVector) -> Output {
  (* Apply rule-based reasoning *)
  rules = load_reasoning_rules("rule_based")

  (* Match query against rules *)
  matched = match_against_rules z rules

  (* Extract result *)
  result = extract_rule_result matched

  return result
}

(* Second reasoning path: Statistical *)
fn solve_with_path_b(z: LatentVector) -> Output {
  (* Apply statistical pattern matching *)
  patterns = load_patterns("statistical")

  (* Score against learned patterns *)
  scores = score_against_patterns z patterns

  (* Select best matching pattern *)
  best_pattern_idx = argmax(scores)
  result = patterns[best_pattern_idx]

  return result
}

(* Third reasoning path: Semantic *)
fn solve_with_path_c(z: LatentVector) -> Output {
  (* Apply semantic similarity *)
  knowledge_graph = load_knowledge_graph()

  (* Find semantically similar entries *)
  similar = find_semantic_matches z knowledge_graph

  (* Aggregate similar results *)
  result = aggregate_semantic_matches similar

  return result
}

(* Compute confidence score for a result *)
fn confidence_score(result: Output) -> Float {
  (* Extract confidence from result structure *)
  if is_map(result) && has_key(result, "confidence") {
    return result["confidence"]
  } else if is_vector(result) {
    (* For probability distributions, take max *)
    return max(result)
  } else {
    (* Default confidence *)
    return 0.5
  }
}

(* Rank results by confidence *)
fn rank_results(confidences: Vector) -> Vector {
  let indexed = []

  for i in range(length(confidences)) {
    indexed = append(indexed, {idx: i, conf: confidences[i]})
  }

  (* Sort by confidence descending *)
  sorted = sort_by(indexed, fn(a, b) { b["conf"] - a["conf"] })

  map(fn(i) { sorted[i]["idx"] }, range(length(sorted)))
}

(* Compute agreement level among results *)
fn compute_agreement_level(results: Vector) -> Float {
  if length(results) <= 1 {
    return 1.0
  }

  let vote_counts = {}

  for i in range(length(results)) {
    let result = to_string(results[i])
    let count = get_count(vote_counts, result, 0)
    vote_counts[result] = count + 1
  }

  let max_count = 0
  for key in keys(vote_counts) {
    if vote_counts[key] > max_count {
      max_count = vote_counts[key]
    }
  }

  return to_float(max_count) / to_float(length(results))
}

(* Weighted vote among results *)
fn weighted_vote(results: Vector, confidences: Vector) -> Output {
  if length(results) != length(confidences) {
    error("Results and confidences must have same length")
  }

  let best_result = results[0]
  let best_confidence = confidences[0]

  for i in range(1, length(results)) {
    if confidences[i] > best_confidence {
      best_result = results[i]
      best_confidence = confidences[i]
    }
  }

  return best_result
}

(* Helper: Get count from map *)
fn get_count(m: Map, key: String, default: Int) -> Int {
  if has_key(m, key) {
    return m[key]
  } else {
    return default
  }
}

(* MindLang Example: Self-Critique Loop
   Demonstrates iterative refinement through self-critique

   This example shows:
   - Problem specification
   - Initial solution generation
   - Critique feedback loop
   - Iterative refinement
   - Confidence-based convergence
   - Final output
*)

program self_critique {
  (* Input problem *)
  query problem_statement -> problem

  (* Encode problem *)
  encode problem -> z

  (* Generate initial solution *)
  initial_solve z -> result

  (* Initialize loop counter *)
  iteration = 0
  max_iterations = 5

  (* Critique loop *)
  loop {
    (* Apply self-critique *)
    critique result -> delta

    (* Extract confidence from critique *)
    confidence = extract_confidence(delta)

    (* Check if confident enough *)
    if confidence > 0.9 || iteration >= max_iterations {
      (* Break loop if confident or max iterations reached *)
      break
    }

    (* Retry with feedback *)
    feedback = extract_feedback(delta)
    result = retry_with_feedback(result, feedback)

    (* Increment counter *)
    iteration = iteration + 1
  }

  (* Detokenize final result *)
  detokenize result -> output

  (* Return with metadata *)
  return {
    output: output,
    iterations: iteration,
    confidence: confidence,
    improved: confidence > 0.9
  }
}

(* Initial problem solving *)
fn initial_solve(z: LatentVector) -> Solution {
  (* First pass: generate solution *)
  direct_solution = generate_solution(z)

  return direct_solution
}

(* Critique a solution *)
fn critique(solution: Solution) -> Critique {
  (* Analyze solution *)
  analysis = analyze_solution(solution)

  (* Generate critique *)
  {
    strengths: analysis["strengths"],
    weaknesses: analysis["weaknesses"],
    confidence: analysis["confidence"],
    suggestions: analysis["suggestions"],
    needs_revision: analysis["confidence"] < 0.9
  }
}

(* Extract confidence score from critique *)
fn extract_confidence(critique: Critique) -> Float {
  if is_map(critique) && has_key(critique, "confidence") {
    return critique["confidence"]
  } else {
    return 0.5
  }
}

(* Extract feedback from critique *)
fn extract_feedback(critique: Critique) -> Feedback {
  if is_map(critique) && has_key(critique, "suggestions") {
    return critique["suggestions"]
  } else {
    return []
  }
}

(* Retry with feedback *)
fn retry_with_feedback(current_solution: Solution, feedback: Feedback) -> Solution {
  (* Enhance solution based on feedback *)
  enhanced = enhance_solution(current_solution, feedback)

  (* Generate improved solution *)
  improved = generate_solution_from_enhanced(enhanced)

  return improved
}

(* Generate initial solution *)
fn generate_solution(z: LatentVector) -> Solution {
  (* Apply problem-specific reasoning *)
  reasoning_layers = []

  (* Layer 1: Understanding *)
  understanding = apply_understanding_layer(z)
  reasoning_layers = append(reasoning_layers, understanding)

  (* Layer 2: Planning *)
  planning = apply_planning_layer(understanding)
  reasoning_layers = append(reasoning_layers, planning)

  (* Layer 3: Execution *)
  execution = apply_execution_layer(planning)
  reasoning_layers = append(reasoning_layers, execution)

  (* Layer 4: Verification *)
  verification = apply_verification_layer(execution)
  reasoning_layers = append(reasoning_layers, verification)

  return execution
}

(* Analyze solution quality *)
fn analyze_solution(solution: Solution) -> Map {
  let scores = {}

  (* Check for logical consistency *)
  consistency = check_consistency(solution)
  scores["consistency"] = consistency

  (* Check for completeness *)
  completeness = check_completeness(solution)
  scores["completeness"] = completeness

  (* Check for clarity *)
  clarity = check_clarity(solution)
  scores["clarity"] = clarity

  (* Compute overall confidence *)
  avg_score = (consistency + completeness + clarity) / 3.0
  scores["confidence"] = avg_score

  (* Identify strengths and weaknesses *)
  scores["strengths"] = identify_strengths(scores)
  scores["weaknesses"] = identify_weaknesses(scores)
  scores["suggestions"] = generate_suggestions(scores)

  return scores
}

(* Check logical consistency *)
fn check_consistency(solution: Solution) -> Float {
  (* Verify that solution components don't contradict *)
  contradictions = find_contradictions(solution)
  consistency = 1.0 - (to_float(length(contradictions)) / 10.0)
  return max(0.0, min(1.0, consistency))
}

(* Check completeness *)
fn check_completeness(solution: Solution) -> Float {
  (* Check if solution addresses all requirements *)
  coverage = compute_coverage(solution)
  return coverage
}

(* Check clarity *)
fn check_clarity(solution: Solution) -> Float {
  (* Check if solution is clearly explained *)
  clarity = measure_clarity(solution)
  return clarity
}

(* Identify strengths *)
fn identify_strengths(scores: Map) -> Vector {
  let strengths = []

  if scores["consistency"] > 0.8 {
    strengths = append(strengths, "Logically consistent")
  }
  if scores["completeness"] > 0.8 {
    strengths = append(strengths, "Addresses all points")
  }
  if scores["clarity"] > 0.8 {
    strengths = append(strengths, "Clearly explained")
  }

  return strengths
}

(* Identify weaknesses *)
fn identify_weaknesses(scores: Map) -> Vector {
  let weaknesses = []

  if scores["consistency"] < 0.7 {
    weaknesses = append(weaknesses, "Some logical inconsistencies")
  }
  if scores["completeness"] < 0.7 {
    weaknesses = append(weaknesses, "Missing some details")
  }
  if scores["clarity"] < 0.7 {
    weaknesses = append(weaknesses, "Could be clearer")
  }

  return weaknesses
}

(* Generate improvement suggestions *)
fn generate_suggestions(scores: Map) -> Vector {
  let suggestions = []

  if scores["consistency"] < 0.8 {
    suggestions = append(suggestions, "Review for logical consistency")
  }
  if scores["completeness"] < 0.8 {
    suggestions = append(suggestions, "Add missing details")
  }
  if scores["clarity"] < 0.8 {
    suggestions = append(suggestions, "Improve explanations")
  }

  return suggestions
}

